const text = $('L1-A Preprocessor').first().json.text.toUpperCase();
const parts = text.split(' ');
const action = parts[0];
const targetId = parseInt(parts[1]);
const newStatus = action === 'APPROVE' ? 'approved' : 'rejected';
return [{ json: { action, targetId, newStatus } }];

const data = $input.first().json;
let reply = data.dify_reply
  || (data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content)
  || data.answer || data.text
  || 'ขออภัย ไม่สามารถตอบได้ตอนนี้ครับ';
if (reply.length > 4096) reply = reply.substring(0, 4090) + '...[ต่อ]';
const agent = data.assigned_agent || (data.model ? 'litellm' : 'unknown');
const model = data.selected_model || data.model || '';

// S4: Tier 3 (Ollama) gets fallback prefix
if (model.startsWith('ollama/')) {
  reply = '[Fallback mode — response may be shorter than usual]\n\n' + reply;
}

return [{ json: { reply, reply_text: reply, agent, model } }];

