// Parse L1-B LiteLLM response
const raw = $input.first().json;
let classification;

try {
  const content = raw.choices[0].message.content;
  // Strip markdown code fences if present
  const cleaned = content.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  classification = JSON.parse(cleaned);
} catch(e) {
  // Fallback: default JOB
  classification = { pillar: 'JOB', domain: 'ops', confidence: 0.8, hitl_required: false, hitl_reason: null, translated_en: '' };
}

// Merge with L1-A data
const l1a = $('L1-A Preprocessor').first().json;

return [{ json: {
  pillar:        classification.pillar       || 'JOB',
  domain:        classification.domain       || 'ops',
  confidence:    classification.confidence   ?? 0.8,
  hitl_required: classification.hitl_required === true,
  hitl_reason:   classification.hitl_reason  || null,
  translated_en: classification.translated_en || l1a.text,
  // Pass through L1-A fields
  text:          l1a.text,
  content_clean: l1a.content_clean,
  userId:        l1a.userId,
  chatId:        l1a.chatId,
  msg_hash:      l1a.msg_hash,
  lang_detected: l1a.lang_detected
}}];

// L3 Context Retriever — hardcoded KB IDs (T2: added SKILL/COURSE/LEARNING → KB-06)
const l1b = $('L1-B Parse').first().json;
const pillar = (l1b.pillar || 'JOB').split('.')[0].toUpperCase();
const query = l1b.text || '';

const KB_06 = '044558e7-3203-40ec-be65-5ec6f812e4b0';
const KB_04 = '64329612-bb5d-4090-8fce-e49499d26379';

const KB_MAP = {
  'JOB':      [KB_04, '4da3b0fe-49ea-4c12-9273-92045b8f9678'],
  'PERSONAL': ['6b35bc3e-3e47-45d0-8dd4-c9a93629fdf3', '4da3b0fe-49ea-4c12-9273-92045b8f9678'],
  'CREATIVE': ['1fa9ce1d-c03a-40a1-9cac-1a935af9b0a1', '4da3b0fe-49ea-4c12-9273-92045b8f9678'],
  'SKILL':    [KB_06, KB_04],
  'COURSE':   [KB_06, KB_04],
  'LEARNING': [KB_06, KB_04],
};
const kbIds = KB_MAP[pillar] || KB_MAP['JOB'];

return [{ json: {
  kb_id:  kbIds[0],
  kb_ids: kbIds,
  query,
  pillar
} }];

// L3 Inject — semantic primary, BM25 fallback (S1 + T3)
const l3prep = $('L3 Prepare').first().json;
const query = l3prep.query || '';

// ── Try semantic results first ─────────────────────────────────────────────
let semanticRows = [];
try {
  const semData = $('L3 Semantic Search').first().json;
  // n8n postgres returns array of row objects
  const allRows = $('L3 Semantic Search').all();
  semanticRows = allRows
    .map(r => r.json)
    .filter(r => r.content && r.content.length > 10 && (r.similarity || 0) > 0.3);
} catch(e) {
  // Semantic failed — Ollama down or no embeddings yet
}

// ── BM25 fallback (original logic) ────────────────────────────────────────
function bm25score(text, q) {
  const words = q.toLowerCase().split(/\s+/).filter(w => w.length > 2);
  const t = (text || '').toLowerCase();
  return words.reduce((s, w) => s + (t.split(w).length - 1), 0);
}

let context = '';
let kb_chunks = 0;
let retrieval_method = 'none';

if (semanticRows.length > 0) {
  context = '### Context from Knowledge Base (semantic):\n' +
    semanticRows.slice(0, 3).map(r => r.content).join('\n---\n');
  kb_chunks = semanticRows.length;
  retrieval_method = 'semantic';
} else {
  // BM25 path
  let segsData;
  try {
    segsData = $('L3 Get Segments').first().json;
  } catch(e) {
    segsData = { data: [] };
  }
  const segments = segsData.data || [];
  const ranked = segments
    .map(seg => ({ content: seg.content || '', score: bm25score(seg.content, query) }))
    .sort((a, b) => b.score - a.score)
    .slice(0, 3)
    .filter(s => s.content.length > 10);

  if (ranked.length > 0) {
    context = '### Context from Knowledge Base:\n' + ranked.map(s => s.content).join('\n---\n');
    kb_chunks = ranked.length;
    retrieval_method = 'bm25';
  }
}

const kb_miss = kb_chunks === 0;
if (kb_miss) context = 'No relevant KB content found for this query.';

const l1b = $('L1-B Parse').first().json;
return [{ json: {
  ...l1b,
  context,
  kb_chunks,
  kb_miss,
  retrieval_method,
  kb_id_used: l3prep.kb_id,
  pillar: l3prep.pillar || l1b.pillar || 'JOB'
} }];

// Build L1-C request body with KB context properly embedded
const l3 = $('L3 Inject Context').first().json;
const l1a = $('L1-A Preprocessor').first().json;

// context may contain quotes/newlines — safe to put in JSON object directly
return [{ json: {
  pillar:  l3.pillar  || 'JOB',
  message: l1a.text   || '',
  user_id: String(l1a.userId || ''),
  context: l3.context || ''
} }];

